import akka.actor.{Actor, ActorLogging, Props}
import scala.math.BigDecimal

object AccountActor {
  // Messages for the actor
  sealed trait Command
  case class Deposit(amount: BigDecimal) extends Command
  case class Withdraw(amount: BigDecimal) extends Command
  case object GetBalance extends Command

  // Responses from the actor
  sealed trait Response
  case class BalanceUpdated(newBalance: BigDecimal) extends Response
  case class InsufficientFunds(currentBalance: BigDecimal, requestedAmount: BigDecimal) extends Response
  case class CurrentBalance(balance: BigDecimal) extends Response
  case class InvalidAmount(amount: BigDecimal) extends Response // For negative deposits/withdrawals

  def props(initialBalance: BigDecimal): Props = Props(new AccountActor(initialBalance))
}

class AccountActor(initialBalance: BigDecimal) extends Actor with ActorLogging {
  import AccountActor._

  // Mutable state for the account balance.
  // This 'var' is safe because Akka actors process messages sequentially,
  // ensuring that only one message handler modifies 'balance' at a time.
  private var balance: BigDecimal = initialBalance

  override def receive: Receive = {
    case Deposit(amount) =>
      if (amount <= BigDecimal(0)) {
        sender() ! InvalidAmount(amount)
      } else {
        balance += amount
        log.info(s"Deposited $amount. New balance: $balance")
        sender() ! BalanceUpdated(balance)
      }

    case Withdraw(amount) =>
      if (amount <= BigDecimal(0)) {
        sender() ! InvalidAmount(amount)
      } else if (balance >= amount) {
        balance -= amount
        log.info(s"Withdrew $amount. New balance: $balance")
        sender() ! BalanceUpdated(balance)
      } else {
        log.warning(s"Insufficient funds for withdrawal of $amount. Current balance: $balance")
        sender() ! InsufficientFunds(balance, amount)
      }

    case GetBalance =>
      sender() ! CurrentBalance(balance)
  }
}